---
import type { ImageMetadata } from "astro"
import { Image } from "astro:assets"
import CheckIcon from "lucide-static/icons/check.svg"

import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  title: string
  description: string
  features?: string[]
  buttons?: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  image: {
    src: ImageMetadata
    alt: string
  }
}

const {
  class: className,
  title,
  description,
  features,
  buttons,
  image,
} = Astro.props
---

<Section class={cn("", className)}>
  <SectionContainer class="grid gap-12 lg:grid-cols-2 lg:items-center">
    <div class="flex flex-col gap-6">
      <div class="flex flex-col gap-4">
        <h2
          class="text-foreground text-3xl leading-[1.1] font-semibold tracking-tight text-balance sm:text-4xl"
        >
          {title}
        </h2>
        <p class="text-muted-foreground text-lg leading-relaxed">
          {description}
        </p>
      </div>
      {
        features?.length && (
          <ul class="flex flex-col gap-3">
            {features.map((feature) => (
              <li class="flex items-center gap-3 text-sm">
                <CheckIcon class="text-primary size-4 shrink-0" />
                {feature}
              </li>
            ))}
          </ul>
        )
      }
      {
        buttons?.length && (
          <div class="flex flex-wrap gap-3">
            {buttons.map(({ href, label, ...button }, index) => (
              <Button
                as="a"
                href={href}
                size="lg"
                variant={
                  button.variant ?? (index === 0 ? "default" : "outline")
                }
                {...button}
              >
                {label}
              </Button>
            ))}
          </div>
        )
      }
    </div>
    <Image
      src={image.src}
      alt={image.alt}
      class="aspect-[4/3] w-full rounded-xl border object-cover"
      widths={[640, 960, 1280]}
      sizes="(min-width: 1024px) 50vw, 100vw"
    />
  </SectionContainer>
</Section>
